// The contrast-safety cross-check dataset, loaded onto the curated-dataset framework
// (issue #860 Track B, wave 2). Copies the mets.ts / icd10-common.ts shape: import the
// envelope JSON (generated by scripts/gen-contrast-safety.ts), validate it once with
// loadDataset(), and expose the contrast-CLASS entries + the allergy/renal gate tables
// (in `meta`) the cross-check consumes. Identity is the class-enum token (fieldStrategy
// "class") — class-enum token matching, NOT RxCUI. The registry lists this for the
// linter; lib/contrast-safety.ts is the DOMAIN cross-check. Pure — no DB, no network.

import rawContrast from "./data/contrast-safety.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type {
  ContrastClassEntry,
  ContrastMeta,
  ContrastAllergyGate,
  ContrastRenalGate,
} from "@/scripts/gen-contrast-safety";

export type {
  ContrastClassEntry,
  ContrastMeta,
  ContrastAllergyGate,
  ContrastRenalGate,
} from "@/scripts/gen-contrast-safety";

// The validated dataset (envelope + guarantees). Throws at module load if the
// committed JSON ever violates the contract — a loud, early failure.
export const contrastDataset = loadDataset<ContrastClassEntry, ContrastMeta>(
  rawContrast
);

// Identity strategy: the class-enum `class` token, case-folded. For the linter.
export const contrastClassStrategy = fieldStrategy("class");

// The contrast classes (entries) + the two per-class gate tables (dataset meta) the
// cross-check consumes.
export const CONTRAST_CLASSES: ContrastClassEntry[] = contrastDataset.entries;
export const CONTRAST_ALLERGY_GATES: ContrastAllergyGate[] = (
  contrastDataset.meta as ContrastMeta
).allergyGates;
export const CONTRAST_RENAL_GATES: ContrastRenalGate[] = (
  contrastDataset.meta as ContrastMeta
).renalGates;
